//! Repository for PurchaseOrderItem entities
//!
//! Originally generated by metaphor-schema; now **user-owned** — this exact path is declared under
//! `user_owned` in `metaphor.codegen.yaml`, so the generator skips it wholesale. The custom methods
//! below hold the hand-written PurchaseOrderItem SQL — the receipt seam's remaining-quantity read and
//! the 3-way-match allocation's locking read + watermark bump (4-layer rule: services orchestrate,
//! repos hold SQL).
//!
//! Thin newtype over `backbone_orm::GenericCrudRepository<PurchaseOrderItem, backbone_orm::SoftDelete>`.
//! All standard CRUD methods are available via `Deref`.

use anyhow::Result;
use rust_decimal::Decimal;
use sqlx::{PgPool, Row};
use uuid::Uuid;

use backbone_orm::company_scope;

use crate::domain::entity::PurchaseOrderItem;

/// Table name for PurchaseOrderItem entities
pub const TABLE_NAME: &str = "buying.purchase_order_items";

/// Repository for PurchaseOrderItem entities.
///
/// All standard CRUD, soft-delete, pagination, and bulk methods are
/// provided automatically via `Deref` to `backbone_orm::GenericCrudRepository`.
pub struct PurchaseOrderItemRepository(
    backbone_orm::GenericCrudRepository<PurchaseOrderItem, backbone_orm::SoftDelete>,
);

impl std::ops::Deref for PurchaseOrderItemRepository {
    type Target = backbone_orm::GenericCrudRepository<PurchaseOrderItem, backbone_orm::SoftDelete>;
    fn deref(&self) -> &Self::Target { &self.0 }
}

impl PurchaseOrderItemRepository {
    /// Create a new repository instance.
    pub fn new(pool: PgPool) -> Self {
        Self(backbone_orm::GenericCrudRepository::new(pool, TABLE_NAME))
    }
}

/// The exact row a purchase-order line insert writes. `line_amount` is the SERVER-computed
/// `money(quantity * rate)`, not anything the caller sent.
pub struct NewPurchaseOrderItemRow<'a> {
    pub id: Uuid,
    pub order_id: Uuid,
    pub company_id: Uuid,
    pub item_id: Uuid,
    pub warehouse_id: Option<Uuid>,
    pub description: Option<&'a str>,
    pub quantity: Decimal,
    pub rate: Decimal,
    pub line_amount: Decimal,
}

/// A PO line's not-yet-received quantity, as requested by the receipt seam.
pub struct RemainingLineRow {
    pub item_id: Uuid,
    pub rate: Decimal,
    pub remaining: Decimal,
}

/// A locked PO line and its remaining capacity against one 3-way-match watermark.
pub struct AllocatableLineRow {
    pub id: Uuid,
    pub capacity: Decimal,
}

/// Which 3-way-match watermark an allocation advances, and the column that caps it.
///
/// The two variants encode the 3-way-match invariant as column pairs: a receipt fills `received_qty`
/// up to the ordered `quantity`; billing fills `billed_qty` up to `received_qty` (invoice ≤ receipt).
/// Modelled as an enum rather than a pair of `&str` because these identifiers are interpolated into
/// SQL — the enum is what keeps that interpolation closed over two known-good column pairs.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum MatchWatermark {
    /// `received_qty`, capped at `quantity`.
    Received,
    /// `billed_qty`, capped at `received_qty`.
    Billed,
}

impl MatchWatermark {
    /// The column this allocation adds to.
    fn col(self) -> &'static str {
        match self {
            MatchWatermark::Received => "received_qty",
            MatchWatermark::Billed => "billed_qty",
        }
    }

    /// The column that caps it.
    fn cap_col(self) -> &'static str {
        match self {
            MatchWatermark::Received => "quantity",
            MatchWatermark::Billed => "received_qty",
        }
    }
}

/// Hand-written PurchaseOrderItem SQL. Lives here (not in the write service) per the module's 4-layer
/// rule. The allocation DECISION (does total capacity cover the quantity? which line takes what?)
/// stays in the service — this layer only locks, reads capacity, and bumps a watermark.
impl PurchaseOrderItemRepository {
    /// Insert one PO line.
    ///
    /// Takes the CALLER'S connection so it commits with its header. The caller has already bound the
    /// company on it (`bind_company_on`) — don't re-bind here.
    pub async fn insert_item(
        &self,
        conn: &mut sqlx::PgConnection,
        l: &NewPurchaseOrderItemRow<'_>,
    ) -> Result<(), sqlx::Error> {
        sqlx::query(
            r#"INSERT INTO buying.purchase_order_items
                (id, order_id, company_id, item_id, warehouse_id, description, quantity, rate, line_amount)
               VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9)"#,
        )
        .bind(l.id).bind(l.order_id).bind(l.company_id).bind(l.item_id).bind(l.warehouse_id).bind(l.description)
        .bind(l.quantity).bind(l.rate).bind(l.line_amount)
        .execute(conn)
        .await?;
        Ok(())
    }

    /// Read a PO's not-yet-received lines (`quantity - received_qty > 0`) for the receipt seam.
    ///
    /// ID-only: no company argument — read-only, rides the request-dedicated connection carrying the
    /// caller's `app.company_id`.
    pub async fn fetch_remaining(
        &self,
        pool: &PgPool,
        order_id: Uuid,
    ) -> Result<Vec<RemainingLineRow>, sqlx::Error> {
        let rows = company_scope::fetch_all_rows_scoped(
            pool,
            sqlx::query(
                r#"SELECT item_id, rate, (quantity - received_qty) AS remaining
                   FROM buying.purchase_order_items
                   WHERE order_id=$1 AND (metadata->>'deleted_at') IS NULL AND (quantity - received_qty) > 0"#,
            ).bind(order_id),
        )
        .await?;
        Ok(rows.iter().map(|r| RemainingLineRow {
            item_id: r.get("item_id"),
            rate: r.get("rate"),
            remaining: r.get("remaining"),
        }).collect())
    }

    /// Lock an item's PO lines `FOR UPDATE` and return each one's remaining capacity against
    /// `watermark`, in fill order (`ORDER BY id`). Correct even when a PO has several lines of the
    /// same item.
    ///
    /// Takes the CALLER'S connection: the lock must be held, and the capacity read must be consistent
    /// with the [`Self::add_to_watermark`] bumps that follow, for the whole allocation. The caller has
    /// already bound the company on it — don't re-bind here.
    pub async fn lock_lines_for_allocation(
        &self,
        conn: &mut sqlx::PgConnection,
        order_id: Uuid,
        item_id: Uuid,
        watermark: MatchWatermark,
    ) -> Result<Vec<AllocatableLineRow>, sqlx::Error> {
        let sql = format!(
            "SELECT id, ({cap_col} - {col}) AS capacity FROM buying.purchase_order_items \
             WHERE order_id=$1 AND item_id=$2 AND (metadata->>'deleted_at') IS NULL ORDER BY id FOR UPDATE",
            cap_col = watermark.cap_col(),
            col = watermark.col(),
        );
        let rows = sqlx::query(&sql).bind(order_id).bind(item_id).fetch_all(conn).await?;
        Ok(rows.iter().map(|r| AllocatableLineRow {
            id: r.get("id"),
            capacity: r.get("capacity"),
        }).collect())
    }

    /// Add `qty` to one line's `watermark` column. Same caller-owned-tx contract as
    /// [`Self::lock_lines_for_allocation`] — it must run under the lock that read the capacity.
    pub async fn add_to_watermark(
        &self,
        conn: &mut sqlx::PgConnection,
        line_id: Uuid,
        watermark: MatchWatermark,
        qty: Decimal,
    ) -> Result<(), sqlx::Error> {
        let sql = format!(
            "UPDATE buying.purchase_order_items SET {col} = {col} + $2 WHERE id=$1",
            col = watermark.col(),
        );
        sqlx::query(&sql).bind(line_id).bind(qty).execute(conn).await?;
        Ok(())
    }
}

backbone_core::impl_crud_repository!(PurchaseOrderItemRepository, PurchaseOrderItem, soft_delete);
